var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"연결이 실패했다고요?","JPN":"連結に失敗した？","ENG":"Did you say the connection failed?","TWN":"連接失敗了？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"응, 증폭터널의 에너지 순환이 완전히 막혔어.","JPN":"うん、増幅トンネルのエネルギー循環が完全に塞がれちゃってる。","ENG":"Yeah. The energy circulation in the amplification tunnel has completely stopped.","TWN":"嗯，增幅隧道的能量循環完全被堵住了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"터널이 막혔다는 건, 가운데 불순물이 끼었다는 뜻일까요?","JPN":"トンネルが塞がっているということは、中に不純物がつかえているってことでしょうか？","ENG":"If the tunnel is blocked, does that mean something got lodged in the middle?","TWN":"隧道被堵住，是中間卡了雜質的意思嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그렇지 않아도 방금 전에 탐지 드론을 보냈는데, 터널의 중간지점에서 고밀도 에너지가 확산 중인 걸 포착했어.","JPN":"さっき探知ドローンを送ったんだが、トンネルの中間地点から高密度のエネルギーが拡散している様子が捕捉された。","ENG":"We just sent a detection drone. It picked up high-density energy spreading from the tunnel's midpoint.","TWN":"我剛才已經派了探測無人機，在隧道中段偵測到高密度能量擴散中。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아무래도 터널이 외부의 간섭을 받고 있는 것 같아.","JPN":"どうやらトンネルが外部からの干渉を受けているようだ。","ENG":"It looks like the tunnel is being interfered with from the outside.","TWN":"看來隧道正受到外部干擾。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"반대쪽도 곤란하겠네요. 우연히 침식체 걸까요?","JPN":"あちらも困っているでしょうね。たまたま入り込んだ侵食体でしょうか？","ENG":"Then the other side must be having trouble too. Could it be a stray C.O.?","TWN":"另一邊肯定也很困擾吧。會不會只是偶然出現的侵蝕體？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식체는 아닐 거야. 차원압력이란 게 출입로도 아닌 곳으로 뚫고 들어올 정도로 만만한 게 아니거든.","JPN":"侵食体ではないはずだ。次元圧力というものは、出入口じゃないところから割って入れるような甘いものではない。","ENG":"Probably not. Dimensional pressure isn't something that can just punch through somewhere that isn't an entry point.","TWN":"不可能是侵蝕體，次元壓力可不是隨便就能從沒有出入口的地方鑽入。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 것들이 터널을 막을 정도의 규모라면, 특정 의도가 개입한 거라고 봐야겠지.","JPN":"トンネルを塞ぐほどの規模なら、特定の意図が介入したと考えた方がいい。","ENG":"If something big enough to block the tunnel appeared, we should assume there's deliberate intent behind it.","TWN":"如果有東西能堵住整條隧道，那就代表背後有明確的意圖。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"타기리온이군요.","JPN":"タギリオンですね。","ENG":"Thagirion.","TWN":"是塔基里翁。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그자에겐 어디로든 횡단할 수 있는 황금나무의 뿌리가 있고, 당신들을 방해할 이유도 명확하니까요.","JPN":"あの者にはどこにでも横断できる黄金の木の根があって、あなたたちを邪魔するはっきりとした理由もあります。","ENG":"She has the roots of the Golden Tree that can cross anywhere, and she has every reason to interfere with you.","TWN":"她擁有能橫跨任何地方的黃金樹根，也有充分理由阻止你們。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"과거와 현재를 연결해줄 허수 에너지의 유입이 차단되면서 출력이 약해지고 있어.","JPN":"過去と現在を繋いでくれる虚数エネルギーの流入が遮断されて、出力が弱まってる。","ENG":"With the inflow of Imaginary Energy meant to connect the past and present cut off, the output is dropping.","TWN":"連接過去與現在的虛空能量流入被切斷，輸出正在下降。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"이대로라면 얼마 못 가 터널의 연결 자체가 끊어지고 말 거야.","JPN":"このままじゃすぐにトンネルの連結そのものが断たれちゃう。","ENG":"At this rate, the tunnel connection itself won't last much longer.","TWN":"再這樣下去，用不了多久隧道連接就會斷裂。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"터널이 끊어지면 과거에 있던 사람들은 어떻게 되지?","JPN":"トンネルの連結が断たれたら、過去にいる人たちはどうなる？","ENG":"What happens to the people in the past if the tunnel is severed?","TWN":"如果隧道斷裂，在過去的人會怎麼樣？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"위상차를 견디지 못하고 소멸하거나, 버틴다면 허수공간으로 튕겨져 나가겠죠.","JPN":"位相の差に耐えられず消滅するか、耐えたとしても虚数空間に弾き飛ばされることになるでしょうね。","ENG":"They'll either be erased because they can't withstand the phase difference, or if they endure it, they'll be flung into imaginary space.","TWN":"無法承受相位差被消滅，或是撐住了，被彈進虛空空間。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 문제를 해결하려면 터널의 병목 현상을 해결할 정도로 더 많은 에너지를 주입해 터널을 확장해야 할 겁니다.","JPN":"この問題を解決するためには、トンネルのボトルネック現象を解決できるだけのエネルギーを注入して、トンネルを拡張しないといけません。","ENG":"To solve this, we'll need to inject enough additional energy to expand the tunnel enough to relieve the bottleneck.","TWN":"要解決這個問題、解除瓶頸，必須注入更多能量、擴張隧道。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그건 무리야. 지금 이것보다 더 많은 에너지를 무슨 수로 확보하겠어?","JPN":"それは無理だよ。今これより大量のエネルギーをどうやって確保するつもり？","ENG":"That's impossible. How are we supposed to secure even more energy than we already have?","TWN":"那不可能。要怎麼取得比現在更多的能量？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할 수 있어요.","JPN":"できますよ。","ENG":"We can do it.","TWN":"可以做得到。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"응? 신지아 회장님이?","JPN":"うん？　ヒメノ会長？","ENG":"Huh? Miss Shin Jia?","TWN":"嗯？沈佳會長？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"우물과 연결되어 있는 얼터니움 여과기의 수를 지금보다 다섯 배, 아니 열 배로 늘려서 증폭터널을 확장하는 거죠. 그럼 문제가 해결될 거에요.","JPN":"イドと繋がっているオルタニウムろ過機の数を今より5倍、いいえ、10倍にして増幅トンネルを拡張するんです。そうすれば問題は解決するでしょう。","ENG":"We just increase the number of Alternium filters connected to the Well by fivefold, no, tenfold, and expand the amplification tunnel. That should solve the problem.","TWN":"把與井相連的黑化永恆之金過濾器數量增加到現在的五倍……不，十倍，擴張增幅隧道。那樣就能解決問題。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"두 배만 늘리는 데도 몇 달은 걸릴 것 같은데, 그게 가능하다고?","JPN":"2倍にするだけでも数か月はかかるはずだが、可能なのか？","ENG":"It would take months just to double them. You're saying that's possible?","TWN":"光是增加到兩倍都得花幾個月，你說這做得到？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 별로 어렵지 않아요.","JPN":"はい、そこまで難しいことでもありません。","ENG":"Yes, it's not that difficult.","TWN":"可以，不算太難。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇게 요정의 힘을 마구잡이로 쓰면 당신의 정신이 망가질 거란 말은 하지 않는 건가요?","JPN":"そうやって妖精の力を使いすぎると、あなたの精神が壊れるとか言わないですよね？","ENG":"And you're not going to mention that using the fairy's power so recklessly will destroy your mind?","TWN":"難道你不打算說嗎？如果像那樣胡亂使用精靈的力量，精神會崩壞。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"大丈夫です。","ENG":"It's okay.","TWN":"沒關係。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"세상을 지키고 싶은 사람이 이런 힘을 가지고 있다면... 누구라도 그렇게 했을 테니까.","JPN":"世界を守りたい人がこの力を持っていたら……誰でもそうしたはずですから。","ENG":"If someone who wanted to protect the world had this power... anyone would do the same.","TWN":"如果有人擁有這樣的力量，又想守護世界……任何人都會這麼做的。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇죠? 사장님?","JPN":"そうですよね？　社長。","ENG":"Right, Boss?","TWN":"對吧？老闆？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 하면 당장의 병목 현상은 해결할 수 있겠군.","JPN":"その方法なら今のボトルネック現象は解決できるだろう。","ENG":"That would solve the immediate bottleneck.","TWN":"這樣確實能暫時解決瓶頸。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 터널을 몇 배로 확장하건, 타기리온으로선 자신의 군세를 그만큼 더 투입하면 그만인 문제야.","JPN":"だがトンネルを何倍に拡張しようとも、タギリオンとしてはその分、自分の軍勢を投入すればいいだけの話だ。","ENG":"But no matter how many times we expand the tunnel, for Thagirion, it would only mean sending in that many more of her forces.","TWN":"但就算把隧道擴張好幾倍，對塔基里翁而言，只要再投入同樣數量的軍隊就行。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"병력을 투입해 소모전을 벌이는 것도, 병력이 한정된 우리에게 압도적으로 불리한 방식이지.","JPN":"兵力を投入し消耗戦を繰り広げるにしても、兵力が限定されている我々には圧倒的に不利だ。","ENG":"And if this turns into a war of attrition, that overwhelmingly favors her, since our numbers are limited.","TWN":"用兵力打消耗戰，對兵力有限的我們來說是壓倒性不利的方式。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 우리에겐, 타기리온에게는 없는 패가 하나 있네.","JPN":"だが我々には、タギリオンにはない切り札が一つある。","ENG":"But we have one card Thagirion doesn't.","TWN":"但我們有一張塔基里翁沒有的王牌。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"난 그 가능성에 모든 걸 걸어보고 싶군.","JPN":"私はその可能性にすべてをかけてみたい。","ENG":"And I would like to stake everything on that possibility.","TWN":"我想把一切賭在那個可能性上。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"타기리온에게 없는 거라면...?","JPN":"タギリオンにはないもの……？","ENG":"Something Thagirion doesn't have...?","TWN":"塔基里翁沒有的東西是……？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아이린 양.","JPN":"アイリーン君。","ENG":"Irene.","TWN":"艾琳小姐。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Yes?","TWN":"是？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"20년 전의 코핀 오브 타기리온을 찾아가면 거기엔 자네의 파노라마가 준비되어 있겠지?","JPN":"20年前のコフィン・オブ・タギリオンを訪ねれば、そこには君のパノラマが用意されているんだろう？","ENG":"If we go find the Coffin of Thagirion from twenty years ago, your Panorama will be prepared there, won't it?","TWN":"如果去找20年前的塔基里翁之棺，那裡應該會有你的全景準備好等著你。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그렇긴 하지만... 과거와 현재는 규칙 때문에 서로 간섭할 수 없다면서요? 그럼, 이제 와서 그걸 부숴도 소용없지 않나요?","JPN":"そのとおりですが……過去と現在は規則のせいでお互い干渉できないのですよね？　だとしたら、今更あれを壊しても無駄ではないでしょうか。","ENG":"That's true, but... didn't you say the past and present can't interfere with each other because of the rules? Then wouldn't breaking it now be pointless?","TWN":"話是沒錯……但不是說過去和現在因為規則，不能互相干涉嗎？那現在再去破壞它不是也沒用嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부수자는 게 아닐세. 우리가 그걸 회수해서 이용해보자는 거지.","JPN":"壊すとは言ってない。我々がそれを回収して利用しようということさ。","ENG":"I'm not suggesting we destroy it. I'm saying we retrieve it and make use of it.","TWN":"不是破壞，是回收並利用它。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"증폭터널을 확장할 매개체로서 말이야.","JPN":"増幅トンネルを拡張する媒体としてね。","ENG":"As a medium to expand the amplification tunnel.","TWN":"作為擴張增幅隧道的媒介。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"파노라마로 증폭터널을...?","JPN":"パノラマで増幅トンネルを……？","ENG":"Use Panorama on the amplification tunnel...?","TWN":"用全景來擴張隧道……？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"확실히, 거울이 통로의 양 끝을 피사체로 삼을 수 있다면, 증폭터널을 몇 번이고 복제할 수 있겠네요.","JPN":"確かに、鏡が通路の両端を被写体にできるとしたら、増幅トンネルを何度も複製できるでしょうね。","ENG":"Certainly, if the mirror can use both ends of the passage as its subjects, then we could duplicate the amplification tunnel over and over.","TWN":"確實，如果那面鏡子能把通道兩端都當作拍攝對象，就能無限複製增幅隧道。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"증폭터널이 계속 늘어나면, 아무리 마왕의 군세가 많아도 틀어 막을 순 없을 테고요!","JPN":"増幅トンネルがどんどん増えれば、いくら魔王の軍勢が多くても完全に塞ぐこともできないでしょうし！","ENG":"And if the amplification tunnel keeps multiplying, then no matter how vast the Demon Lord's army is, it won't be able to block it!","TWN":"只要增幅隧道不斷增加，就算魔王軍再多也擋不住！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"하지만 그 파노라마라는 걸 어떻게 가져오지? 달님 팀한테 그런 게 필요하다고 연락할 수단이 없잖아.","JPN":"でも、そのパノラマってどうやって持ってくるの？　お月様チームにそんなものが必要だって連絡する方法がないじゃん。","ENG":"But how are we supposed to get that Panorama? We have no way to contact Team Moon and tell them they need it.","TWN":"但要怎麼取得那個全景？我們又沒辦法聯絡月亮小隊。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우물에서 뒤로 스무 걸음.","JPN":"イドから後ろに20歩。","ENG":"Twenty paces behind the Well.","TWN":"從井往後走二十步。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"...응?","JPN":"……うん？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그쯤에서 바닥을 파보겠나?","JPN":"その辺りで地面を掘ってくれるかい？","ENG":"Would you dig into the ground around there?","TWN":"在那附近挖一下地面吧？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"이건, 레코더잖아? 되게 아날로그스러운 디자인이네.","JPN":"これ、レコーダー？　すごいアナログチックなデザインだね。","ENG":"This is... a recorder. The design feels really analog.","TWN":"這不是……錄音機嗎？設計也太復古了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저건...?","JPN":"あれは……？","ENG":"That's...?","TWN":"那是……？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이쪽은 힐데... 아니, 달님 팀이다.","JPN":"こちらヒルデ……ではなく、お月様チームだ。","ENG":"This is Hilde– I mean, Team Moon.","TWN":"這裡是希爾德……不，月亮小隊。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"통신인가? 신호는 여전히 닿지 않을 텐데 어떻게 된 거지?","JPN":"通信？　今も信号は届かないはずが、どういうことだ？","ENG":"A transmission? But the signal still shouldn't be able to get through. How is this happening?","TWN":"通訊？不是應該還是收不到訊號嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"관리자가 우려한대로 타기리온이 개입하고 있어. 그래서 만일을 위해 갖고 있던 아티펙트를 쓰게 됐다.","JPN":"管理者が心配していたとおり、タギリオンが介入している。それで万が一のためにと持っていたアーティファクトを使うことにした。","ENG":"Just as the Administrator feared, Thagirion is interfering. So we were forced to use the Artifact we'd kept in reserve.","TWN":"跟管理者擔心的一樣，塔基里翁果然介入了。所以我們使用了以防萬一準備的人造神器。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"예니카 씨가 갖고 있던 타임캡슐이군요.","JPN":"イェニカさんが持っていたタイムカプセルですね。","ENG":"That's the Time Capsule Yanikka had.","TWN":"是耶妮卡帶著的時空膠囊。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 타임캡슐은 회신이 불가능한 단방향 통신이야.","JPN":"このタイムカプセルは返信ができない一方向通信だ。","ENG":"This Time Capsule is a one-way transmission device that can't receive replies.","TWN":"這個時空膠囊是一種無法回覆的單向通訊。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"단순한 녹음기와 차이점이 있다면, 땅에 파묻은 순간부터 누가 관측하기 전까지 모든 시간대에 동시에 존재하는 물건이 된다는 거지.","JPN":"普通の録音機と違うところは、地面に埋めた瞬間から誰かが観測するまで、すべての時間帯に同時に存在する物体となることだな。","ENG":"The difference between it and an ordinary recorder is that, from the moment it is buried in the ground until someone observes it, it exists simultaneously across all time periods.","TWN":"和普通錄音機不同的是只要被埋進土裡，在被任何人觀測到之前，它會同時存在於所有時間點。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그렇다는 건, 우물을 통하지 않아도 과거와 자유롭게 교신이 가능하단 건가?","JPN":"ということは、イドを介さなくても過去と自由に交信できるということか？","ENG":"So that means we can communicate freely with the past even without going through the Well?","TWN":"也就是說不需要透過井，也能與過去自由通訊？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"엄청나게 유용한 물건이잖아?!","JPN":"めちゃくちゃ便利なグッズじゃん！？","ENG":"That's insanely useful, isn't it?!","TWN":"這也太實用了吧？！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"문제는 사용 횟수의 제한이다.","JPN":"問題は使用回数の制限だ。","ENG":"The problem is the limit on how many times it can be used.","TWN":"問題是使用次數有限。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어느 시간대에서나 관측될 가능성이 있다고는 하지만, 한 번 관측되는 순간 그 시간대에선 관측될 가능성이 배제되지.","JPN":"どの時間帯でも観測される可能性があるとはいえ、一度観測されたら、その時間帯では他の観測可能性が排除される。","ENG":"It may be possible to be observed in any time period, but the moment it is observed once, the possibility of it being observed in that time period is eliminated.","TWN":"雖然在任何時間點都可能被觀測，但一旦被某個時間點觀測到，就不會再在那個時間點出現。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"즉, 우리도 너희도 단 한 번만 메시지를 보낼 수 있다는 점에 유의하도록.","JPN":"つまり、こちらもそちらもメッセージを送れるのはたった一度きりという点に注意してくれ。","ENG":"In other words, keep in mind that both sides can only send a single message.","TWN":"也就是說，要留意我們和你們都只能發送一次訊息。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우린 현재 대우물을 완성하고 가동에 성공한 상태지만 타기리온의 수작으로 증폭터널이 막혔다.","JPN":"私たちは現在大イドを完成させ稼働に成功した状態だが、タギリオンの策略により増幅トンネルが塞がれている。","ENG":"We have currently completed and activated the Great Well, but the amplification tunnel has been blocked by one of Thagirion's tricks.","TWN":"我們現在已經完成並啟動大井，但塔基里翁堵住了增幅隧道。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어떻게 대응할지 방법을 알려주면, 이쪽도 지시에 따르도록 하지.","JPN":"どう対応すればいいか方法を教えてくれたら、こちらも指示に従うとしよう。","ENG":"Tell us how to respond, and we'll follow your instructions from this side.","TWN":"請告訴我們該如何應對，我們會按照指示行動。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다 묻었어요!","JPN":"埋めました！","ENG":"It's all buried!","TWN":"已經埋好了！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"정말 이렇게 땅에 묻으면 사장님이 보실까요?","JPN":"本当にこうやって地面に埋めておけば、社長に見ていただけるんでしょうか？","ENG":"If we really bury it in the ground like this, will the Boss actually see it?","TWN":"真的只要埋在地裡，老闆就會看到嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"애초에 그 녀석의 계획이니까. 증폭터널의 이상반응을 그쪽에서도 눈치챘다면 확인할 거다.","JPN":"そもそもあいつの計画だからな。増幅トンネルの異常反応にあちらも気づいたら確認するだろう。","ENG":"It was his plan from the start. If they noticed the abnormal reaction in the amplification tunnel from that side, they'll check.","TWN":"那本來就是他的計畫。如果那邊也察覺到增幅隧道有異常反應，他們就會來確認。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 타임캡슐이란 거... 정말로 써야 할 때가 오는구나.","JPN":"そのタイムカプセルってやつ……本当に使う時が来たんだね。","ENG":"So the time really came to use that Time Capsule...","TWN":"真的到了……要使用那個時空膠囊的時候。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사용법을 들을 때만 해도 이런 쓰기 까다로운 아티펙트를 왜 가져가나 싶었는데.","JPN":"使用方法を聞いた時には、こんなややこしいアーティファクトをなんで持って行くんだって思ったけど。","ENG":"Even when I first heard how to use it, I wondered why we were bringing such a troublesome Artifact along.","TWN":"當初聽到使用方式時，我還想為什麼要帶這種麻煩的人造神器。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"나한테 타임머신에 대해 얘기해준 녀석.","JPN":"私にタイムマシンについて教えてくれた奴。","ENG":"The one who told me about the time machine.","TWN":"告訴我時光機的那個傢伙。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아마도 펠릭스랑 아는 관계일 거야. 비슷한 냄새가 났거든.","JPN":"たぶんフェリックスと知り合いだよ。似たような匂いがしたから。","ENG":"That person probably knows Felix somehow. They smelled similar.","TWN":"可能認識緋莉克絲，他們味道很像。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"...놀아나고 있는 걸지도 모르겠군.","JPN":"……弄ばれてるのかもしれないな。","ENG":"...We may be dancing in the palm of their hand.","TWN":"……或許我們正被操控著。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 뭐라고?","JPN":"うん？　何？","ENG":"Huh? What was that?","TWN":"嗯？你說什麼？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아무것도 아니다.","JPN":"何でもない。","ENG":"Nothing.","TWN":"沒什麼。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들 워치에 이터니움을 충분히 보충해둬라.","JPN":"みんな、ウォッチにエタニウムを十分補充しておけ。","ENG":"Everyone, make sure your Watches are fully stocked with Eternium.","TWN":"大家補滿手錶裡的永恆之金。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"해님 팀에서 어떤 판단을 내리든, 차원터널은 우리가 직접 뚫어야 할 테니까.","JPN":"お日様チームでどんな判断をしようとも、次元トンネルは私たちが直接切り開かないといけないからな。","ENG":"No matter what decision Team Sun makes, we'll have to break through the dimensional tunnel ourselves.","TWN":"不管太陽小隊那邊怎麼判斷，都得由我們自己打通次元隧道。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};